import React, { useState, useEffect, useRef, useMemo } from 'react';
import './NewsAggregator.css';

// Squarified treemap layout algorithm.
// Produces cells whose aspect ratios are as close to square as possible,
// which keeps headlines readable (no thin one-character-wide columns).
function treemap(data, width, height) {
  if (data.length === 0) return [];

  const totalValue = data.reduce((sum, item) => sum + item.value, 0);
  const totalArea = width * height;
  const items = data.map(item => ({
    ...item,
    area: (item.value / totalValue) * totalArea
  }));

  const result = [];

  // Worst (largest) aspect ratio in a row laid out along a side of length `side`.
  function worstRatio(row, side) {
    const sum = row.reduce((s, it) => s + it.area, 0);
    const max = Math.max(...row.map(it => it.area));
    const min = Math.min(...row.map(it => it.area));
    const side2 = side * side;
    const sum2 = sum * sum;
    return Math.max((side2 * max) / sum2, sum2 / (side2 * min));
  }

  function squarify(remaining, x, y, w, h) {
    if (remaining.length === 0) return;
    if (remaining.length === 1) {
      result.push({ ...remaining[0], x, y, w, h });
      return;
    }

    const shortSide = Math.min(w, h);
    let row = [];
    let rest = remaining.slice();
    let bestWorst = Infinity;

    while (rest.length > 0) {
      const candidate = row.concat([rest[0]]);
      const candidateWorst = worstRatio(candidate, shortSide);
      if (row.length === 0 || candidateWorst <= bestWorst) {
        row = candidate;
        bestWorst = candidateWorst;
        rest.shift();
      } else {
        break;
      }
    }

    const rowArea = row.reduce((s, it) => s + it.area, 0);

    if (w >= h) {
      // Lay the row out as a vertical strip on the left.
      const stripWidth = rowArea / h;
      let offsetY = y;
      for (const it of row) {
        const itemHeight = it.area / stripWidth;
        result.push({ ...it, x, y: offsetY, w: stripWidth, h: itemHeight });
        offsetY += itemHeight;
      }
      squarify(rest, x + stripWidth, y, w - stripWidth, h);
    } else {
      // Lay the row out as a horizontal strip on top.
      const stripHeight = rowArea / w;
      let offsetX = x;
      for (const it of row) {
        const itemWidth = it.area / stripHeight;
        result.push({ ...it, x: offsetX, y, w: itemWidth, h: stripHeight });
        offsetX += itemWidth;
      }
      squarify(rest, x, y + stripHeight, w, h - stripHeight);
    }
  }

  squarify(items, 0, 0, width, height);
  return result;
}

// Auto-size text to fit its own box using dichotomy approach.
// More efficient than linear search, with fine-tuning for accuracy.
function autoSizeText(element) {
  const availableWidth = element.clientWidth;
  const availableHeight = element.clientHeight;
  if (availableWidth === 0 || availableHeight === 0) return;

  const minSize = 8;
  const maxSize = 48;

  // Phase 1: Grow from minSize with large increments until overflow
  let fontSize = minSize;
  let increment = 4;

  while (fontSize < maxSize) {
    element.style.fontSize = fontSize + 'px';
    if (element.scrollWidth > availableWidth || element.scrollHeight > availableHeight) {
      break;
    }
    fontSize += increment;
  }

  // Phase 2: Backtrack and fine-tune with smaller increments
  fontSize = Math.max(minSize, fontSize - increment);
  increment = 1;

  while (fontSize < maxSize) {
    element.style.fontSize = fontSize + 'px';
    if (element.scrollWidth > availableWidth || element.scrollHeight > availableHeight) {
      fontSize -= increment;
      break;
    }
    fontSize += increment;
  }

  element.style.fontSize = Math.max(minSize, fontSize) + 'px';
}

// Fisher-Yates shuffle to distribute colors evenly across grid
function shuffle(arr) {
  const shuffled = [...arr];
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }
  return shuffled;
}

const NewsAggregator = ({ articles, visibleCategories, setVisibleCategories, showFooter = true }) => {
  const [layout, setLayout] = useState([]);
  const containerRef = useRef(null);

  const categoryColors = {
    us: '#3D5A72',
    world: '#5A7A8C',
    business: '#4A6A4F',
    technology: '#6B5A8A',
    entertainment: '#A85578',
    sports: '#B36844',
    science: '#3A8C89',
    health: '#A84646'
  };

  // Shuffle and filter articles so colors are distributed across grid
  const visibleArticles = useMemo(() => {
    let filtered = articles.filter(article => visibleCategories[article.category]);
    return shuffle(filtered);
  }, [articles, visibleCategories]);

  // Calculate layout
  useEffect(() => {
    if (!containerRef.current) return;

    const width = containerRef.current.clientWidth;
    const height = containerRef.current.clientHeight;

    // Uniform grid layout: all cards same size
    const cols = Math.ceil(Math.sqrt(visibleArticles.length));
    const rows = Math.ceil(visibleArticles.length / cols);
    const cardWidth = width / cols;
    const cardHeight = height / rows;

    const newLayout = visibleArticles.map((article, idx) => {
      const row = Math.floor(idx / cols);
      const col = idx % cols;
      return {
        id: article.id,
        index: idx,
        x: col * cardWidth,
        y: row * cardHeight,
        w: cardWidth,
        h: cardHeight
      };
    });

    setLayout(newLayout);
  }, [visibleArticles]);

  // Auto-size text when layout changes
  useEffect(() => {
    document.querySelectorAll('.news-headline').forEach(element => {
      autoSizeText(element);
    });
  }, [layout]);

  const handleCategoryToggle = (category) => {
    setVisibleCategories(prev => ({
      ...prev,
      [category]: !prev[category]
    }));
  };

  const handleCardClick = (link) => {
    if (link) window.open(link, '_blank');
  };

  const formatCategoryName = (category) => {
    if (category === 'us') return 'U.S.';
    return category.charAt(0).toUpperCase() + category.slice(1);
  };

  return (
    <div className="news-aggregator">
      <header className="header">
        <h1>News Aggregator</h1>
        <span className="article-count">Top Headlines</span>
      </header>

      <div className="container" ref={containerRef}>
        {visibleArticles.map((article, idx) => {
          const layoutItem = layout.find(l => l.index === idx);
          if (!layoutItem) return null;

          return (
            <div
              key={article.id}
              className="news-card"
              style={{
                position: 'absolute',
                left: layoutItem.x + 'px',
                top: layoutItem.y + 'px',
                width: layoutItem.w + 'px',
                height: layoutItem.h + 'px',
                backgroundColor: categoryColors[article.category],
                cursor: 'pointer'
              }}
              onClick={() => handleCardClick(article.link)}
            >
              <h2 className="news-headline">{article.title}</h2>
              <div className="news-source">{article.source}</div>
            </div>
          );
        })}
      </div>

      <footer className="footer">
        <div className="category-filters">
          {Object.keys(categoryColors).map(category => (
            <label key={category} className="filter-label">
              <input
                type="checkbox"
                checked={visibleCategories[category]}
                onChange={() => handleCategoryToggle(category)}
                className="filter-checkbox"
              />
              <span>{formatCategoryName(category)}</span>
            </label>
          ))}
        </div>
      </footer>
    </div>
  );
};

export default NewsAggregator;
